phase1.code:
#include <iostream>
#include <string>

int main() {
    std::string playerName;
    int playerAge;

    // Ask for input
    std::cout << "Welcome, adventurer!" << std::endl;
    std::cout << "What is your name? ";
    std::cin >> playerName;

    std::cout << "How old are you, " << playerName << "? ";
    std::cin >> playerAge;

    std::cout << "\n=== Character Sheet ===" << std::endl;
    std::cout << "Name: " << playerName << std::endl;
    std::cout << "Age: " << playerAge << std::endl;

    // Input with multiple words
    std::cin.ignore();  // Clear the buffer
    std::string fullName;
    std::cout << "Enter your full name (with spaces): ";
    std::getline(std::cin, fullName);
    std::cout << "Full name: " << fullName << std::endl;

    return 0;
}

