phase3.solution:
#include <iostream>
#include <string>

int main() {
    std::string characterClass;
    int level;

    std::cout << "Enter your class (Warrior/Mage/Rogue): ";
    std::getline(std::cin, characterClass);

    std::cout << "Enter your starting level: ";
    std::cin >> level;

    std::cout << "\n=== Character Created ===" << std::endl;
    std::cout << "Class: " << characterClass << std::endl;
    std::cout << "Starting Level: " << level << std::endl;

    return 0;
}
